<?php namespace App\Repositories\Assessment;use App\Repositories\BaseRepository;use App\Models\Assessment\GradingSystem;use Illuminate\Database\Eloquent\Collection;class GradingSystemRepository extends BaseRepository{    public function __construct(GradingSystem $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByName(string $name): ?GradingSystem    {        return $this->query()->where('name', $name)->first();    }    public function getActiveSystems(): Collection    {        return $this->query()->where('is_active', true)->get();    }    public function getByAcademicYear(int $academicYearId): Collection    {        return $this->findByField('academic_year_id', $academicYearId);    }    public function getByClass(int $classId): ?GradingSystem    {        return $this->query()->where('class_id', $classId)->first();    }    public function getDefaultSystem(): ?GradingSystem    {        return $this->query()->where('is_default', true)->where('is_active', true)->first();    }    public function setDefault(int $id): bool    {        $this->query()->where('is_default', true)->update(['is_default' => false]);        return $this->update($id, ['is_default' => true]);    }    public function searchSystems(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }}